// components/PwaInstallBanner.tsx
import { useEffect, useState } from 'react';
import { X, Plus } from 'lucide-react';

export function PwaInstallBanner() {
  const [prompt, setPrompt] = useState<any>(null);
  const [dismissed, setDismissed] = useState(false);

  useEffect(() => {
    const stored = localStorage.getItem('pwa-dismissed');
    if (stored) { setDismissed(true); return; }

    const handler = (e: any) => {
      e.preventDefault();
      setPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  if (!prompt || dismissed) return null;

  const dismiss = () => {
    setDismissed(true);
    localStorage.setItem('pwa-dismissed', 'true');
  };

  const install = async () => {
    prompt.prompt();
    const { outcome } = await prompt.userChoice;
    if (outcome === 'accepted') dismiss();
  };

  return (
    <div
      role="region"
      aria-label="Install app"
      className="fixed inset-x-0 top-0 z-40 bg-blue-600 text-white px-4 py-3 flex items-center gap-3"
      style={{ paddingTop: 'max(0.75rem, env(safe-area-inset-top))' }}
    >
      <Plus className="h-5 w-5 flex-none" />
      <span className="flex-1 text-sm">Install our app for a better experience</span>
      <button onClick={install} className="min-h-9 px-3 rounded bg-white text-blue-600 text-sm font-medium">Install</button>
      <button onClick={dismiss} aria-label="Dismiss" className="flex h-9 w-9 items-center justify-center"><X className="h-4 w-4" /></button>
    </div>
  );
}

