import { useState, useRef } from 'react';

export function ZoomableImage({ src, alt }: { src: string; alt: string }) {
  const [scale, setScale] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  const onWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    setScale((s) => Math.max(1, Math.min(5, s * (e.deltaY < 0 ? 1.1 : 0.9))));
  };

  const onDoubleClick = () => {
    if (scale > 1) {
      setScale(1);
      setOffset({ x: 0, y: 0 });
    } else {
      setScale(2);
    }
  };

  // Pinch/pan logic via pointer events (simplified)
  // Full implementation: track 2 pointers, compute distance, apply scale

  return (
    <div
      ref={containerRef}
      onWheel={onWheel}
      onDoubleClick={onDoubleClick}
      className="relative overflow-hidden w-full h-full bg-black cursor-grab"
      style={{ touchAction: 'none' }}
    >
      <img
        src={src}
        alt={alt}
        className="w-full h-full object-contain transition-transform"
        style={{ transform: `scale(${scale}) translate(${offset.x}px, ${offset.y}px)` }}
      />
    </div>
  );
}

