// components/LiveTable.tsx
import { useEffect, useRef, useState } from 'react';

type Row = { id: string; value: number };

export function LiveTable({ rows }: { rows: Row[] }) {
  const prevValues = useRef(new Map<string, number>());
  const [flashing, setFlashing] = useState(new Set<string>());

  useEffect(() => {
    const newFlash = new Set<string>();
    rows.forEach((r) => {
      const prev = prevValues.current.get(r.id);
      if (prev !== undefined && prev !== r.value) {
        newFlash.add(r.id);
      }
      prevValues.current.set(r.id, r.value);
    });
    if (newFlash.size > 0) {
      setFlashing((f) => new Set([...f, ...newFlash]));
      setTimeout(() => {
        setFlashing((f) => {
          const next = new Set(f);
          newFlash.forEach((id) => next.delete(id));
          return next;
        });
      }, 1000);
    }
  }, [rows]);

  return (
    <table className="w-full text-sm">
      <tbody>
        {rows.map((r) => (
          <tr
            key={r.id}
            className={`
              border-b transition-colors
              ${flashing.has(r.id) ? 'bg-yellow-100' : ''}
            `}
          >
            <td className="px-3 py-2">{r.id}</td>
            <td className="px-3 py-2 text-right tabular-nums">{r.value}</td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

