import { useState } from 'react';
import { X } from 'lucide-react';

export function MultiSelect({ selected, onChange, options }: { selected: string[]; onChange: (s: string[]) => void; options: string[] }) {
  const [query, setQuery] = useState('');
  const available = options.filter((o) => !selected.includes(o) && o.toLowerCase().includes(query.toLowerCase()));

  const remove = (item: string) => onChange(selected.filter((s) => s !== item));
  const add = (item: string) => { onChange([...selected, item]); setQuery(''); };

  return (
    <div>
      <div className="flex flex-wrap gap-2 min-h-11 p-2 rounded border bg-white">
        {selected.map((item) => (
          <span key={item} className="flex items-center gap-1 rounded-full bg-blue-100 px-2 py-1 text-sm">
            {item}
            <button
              type="button"
              onClick={() => remove(item)}
              aria-label={`Remove ${item}`}
              className="flex h-6 w-6 items-center justify-center -mr-1 hover:bg-blue-200 rounded-full"
            ><X className="h-3 w-3" /></button>
          </span>
        ))}
        <input
          type="text"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Backspace' && !query && selected.length > 0) {
              remove(selected[selected.length - 1]);
            }
          }}
          placeholder="Add tag"
          className="flex-1 min-w-[120px] outline-none text-base"
        />
      </div>
      {query && available.length > 0 && (
        <ul className="mt-1 rounded border bg-white shadow-lg max-h-48 overflow-y-auto">
          {available.map((o) => (
            <li key={o}>
              <button
                type="button"
                onClick={() => add(o)}
                className="block w-full text-left min-h-11 px-3 hover:bg-neutral-50"
              >{o}</button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

