// context/ModalStack.tsx
import { createContext, useContext, useState, useCallback } from 'react';

type ModalStackContext = {
  push: (id: string) => void;
  pop: (id: string) => void;
  top: string | null;
};

const Ctx = createContext<ModalStackContext | null>(null);

export function ModalStackProvider({ children }: { children: React.ReactNode }) {
  const [stack, setStack] = useState<string[]>([]);

  const push = useCallback((id: string) => setStack((s) => [...s, id]), []);
  const pop = useCallback((id: string) => setStack((s) => s.filter((x) => x !== id)), []);
  const top = stack[stack.length - 1] ?? null;

  return <Ctx.Provider value={{ push, pop, top }}>{children}</Ctx.Provider>;
}

export const useModalStack = () => useContext(Ctx);

