import { useElementSize } from '@/hooks/useElementSize';

type Stroke = { points: { x: number; y: number }[]; color: string };

export function ScalingWhiteboard({ strokes }: { strokes: Stroke[] }) {
  const [ref, { width, height }] = useElementSize<HTMLDivElement>();
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || width === 0) return;
    canvas.width = width;
    canvas.height = height;
    const ctx = canvas.getContext('2d')!;
    ctx.clearRect(0, 0, width, height);

    strokes.forEach((stroke) => {
      ctx.strokeStyle = stroke.color;
      ctx.lineWidth = 2;
      ctx.beginPath();
      stroke.points.forEach((p, i) => {
        const x = p.x * width;
        const y = p.y * height;
        if (i === 0) ctx.moveTo(x, y);
        else ctx.lineTo(x, y);
      });
      ctx.stroke();
    });
  }, [width, height, strokes]);

  return (
    <div ref={ref} className="relative h-dvh w-full">
      <canvas ref={canvasRef} className="block" />
    </div>
  );
}

// Similar pattern to responsive-100 (VS Code) but 4 panes
