import { useState } from 'react';
import { useBreakpoint } from '@/hooks/useBreakpoint';

export function DiscordLayout({ servers, channels, chat, members }: { servers: React.ReactNode; channels: React.ReactNode; chat: React.ReactNode; members: React.ReactNode }) {
  const bp = useBreakpoint();

  if (bp === 'wide') {
    return (
      <div className="grid h-dvh grid-cols-[72px_240px_1fr_280px] divide-x">
        <aside className="bg-neutral-900">{servers}</aside>
        <aside>{channels}</aside>
        <main>{chat}</main>
        <aside>{members}</aside>
      </div>
    );
  }

  if (bp === 'desktop') {
    return (
      <div className="grid h-dvh grid-cols-[72px_240px_1fr] divide-x">
        <aside className="bg-neutral-900">{servers}</aside>
        <aside>{channels}</aside>
        <main>{chat}</main>
      </div>
    );
  }

  // tablet + mobile: chat primary, others as drawers
  return (
    <div className="flex flex-col h-dvh">
      <main className="flex-1">{chat}</main>
      {/* Drawers for servers/channels/members triggered by buttons */}
    </div>
  );
}

import { useVirtualizer } from '@tanstack/react-virtual';
export function DynamicTable({ rows }) {
  const parentRef = React.useRef(null);
  const v = useVirtualizer({ count: rows.length, getScrollElement: () => parentRef.current, estimateSize: () => 56, measureElement: el => el.getBoundingClientRect().height, overscan: 10 });
  return <div ref={parentRef} style={{ overflow: 'auto', maxHeight: '70dvh' }}><div style={{ height: v.getTotalSize(), position: 'relative' }}>{v.getVirtualItems().map(item => <div key={rows[item.index].id} ref={v.measureElement} style={{ position: 'absolute', transform: `translateY(${item.start}px)`, width: '100%' }}><ResponsiveRow row={rows[item.index]} /></div>)}</div></div>;
}

// components/TimePicker.tsx
import { useState } from 'react';
import { useMediaQuery } from '@/hooks/useMediaQuery';

export function TimePicker({ value, onChange, label }: { value: string; onChange: (v: string) => void; label: string }) {
  const isTouch = useMediaQuery('(pointer: coarse)', true);
  const [open, setOpen] = useState(false);

  if (isTouch) {
    return (
      <label className="block">
        <span className="text-sm font-medium">{label}</span>
        <input
          type="time"
          value={value}
          onChange={(e) => onChange(e.target.value)}
          className="mt-1 block w-full min-h-11 rounded border px-3 text-base"
        />
      </label>
    );
  }

  // Desktop: dropdown with 15-min increments
  const times: string[] = [];
  for (let h = 0; h < 24; h++) {
    for (let m = 0; m < 60; m += 15) {
      times.push(`${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`);
    }
  }

  return (
    <label className="block relative">
      <span className="text-sm font-medium">{label}</span>
      <button
        type="button"
        onClick={() => setOpen(true)}
        className="mt-1 block w-full min-h-10 rounded border bg-white px-3 text-left text-sm"
      >{value || 'Select time'}</button>
      {open && (
        <div className="absolute z-30 mt-1 max-h-60 w-full overflow-y-auto rounded border bg-white shadow-lg">
          {times.map((t) => (
            <button
              key={t}
              type="button"
              onClick={() => { onChange(t); setOpen(false); }}
              className={`block w-full px-3 py-2 text-left text-sm hover:bg-neutral-50 ${t === value ? 'bg-blue-50 font-medium' : ''}`}
            >{t}</button>
          ))}
        </div>
      )}
    </label>
  );
}

// components/FocalHero.tsx
export function FocalHero({ src, alt, focal = '50% 50%' }: { src: string; alt: string; focal?: string }) {
  return (
    <div className="relative w-full aspect-[2/1] sm:aspect-[3/1] lg:aspect-[4/1] overflow-hidden bg-neutral-200">
      <img
        src={src}
        alt={alt}
        className="absolute inset-0 h-full w-full object-cover"
        style={{ objectPosition: focal }}
      />
    </div>
  );
}

