// Already detailed in responsive-027. Quick variant:
export function WizardProgress({ currentStep, totalSteps, stepLabel }: { currentStep: number; totalSteps: number; stepLabel: string }) {
  const pct = (currentStep / totalSteps) * 100;
  return (
    <div role="progressbar" aria-valuenow={currentStep} aria-valuemin={1} aria-valuemax={totalSteps} aria-label={`Step ${currentStep} of ${totalSteps}: ${stepLabel}`}>
      <div className="flex items-baseline justify-between mb-1">
        <h2 className="text-lg font-medium">{stepLabel}</h2>
        <span className="text-sm text-neutral-500 tabular-nums">{currentStep}/{totalSteps}</span>
      </div>
      <div className="h-2 rounded-full bg-neutral-200 overflow-hidden">
        <div className="h-full bg-blue-500 transition-[width] duration-300" style={{ width: `${pct}%` }} />
      </div>
    </div>
  );
}
